#!/usr/bin/env python3\n# -*- coding: utf-8 -*-\n\"\"\"\nclip_pool.py — Video Vault featuring 9D Semantic Vector Space.\nSpeeds up loading times in O(1) by sync-loading pre-matched weedit_db.json clips.\n\"\"\"\n\nfrom __future__ import annotations\n\nimport json\nimport os\nimport re\nfrom dataclasses import dataclass, field\nfrom pathlib import Path\nfrom typing import Dict, List, Optional, Tuple\n\nimport cv2\nimport numpy as np\nfrom scipy.spatial.distance import cosine\n\nVECTOR_DIM = 9\nVIDEO_EXTS  = {\".mp4\", \".mov\", \".avi\", \".mkv\", \".webm\", \".m4v\"}\n\n# Semantic vector mappings\n_GENRE_KEYWORDS: Dict[str, List[str]] = {\n    \"genre_hiphop\":     [\"hip\", \"hop\", \"hiphop\", \"rap\", \"trap\", \"drill\", \"grime\", \"street\", \"urban\"],\n    \"genre_pop\":        [\"pop\", \"dance\", \"edm\", \"synth\", \"chart\", \"bright\", \"colorful\"],\n    \"genre_electronic\": [\"electronic\", \"techno\", \"house\", \"trance\", \"ambient\", \"abstract\", \"drone\"],\n    \"genre_rock\":       [\"rock\", \"metal\", \"punk\", \"grunge\", \"indie\", \"wide\", \"dramatic\"],\n    \"genre_soul\":       [\"soul\", \"rnb\", \"r&b\", \"funk\", \"gospel\", \"blues\", \"jazz\", \"intimate\"],\n}\n\n_MOOD_KEYWORDS: Dict[str, List[str]] = {\n    \"mood_happy\":   [\"happy\", \"joy\", \"euphoric\", \"upbeat\", \"positive\", \"fun\", \"bright\"],\n    \"mood_intense\": [\"intense\", \"dark\", \"aggressive\", \"angry\", \"hard\", \"fierce\", \"energetic\", \"action\"],\n    \"mood_calm\":    [\"calm\", \"chill\", \"slow\", \"soft\", \"mellow\", \"smooth\", \"relax\", \"static\"],\n}\n\n_SHOT_TAGS   = [\"wide\", \"close\", \"medium\", \"drone\", \"pov\", \"extreme\", \"aerial\"]\n_MOTION_TAGS = [\"pan\", \"zoom\", \"orbit\", \"static\", \"tracking\", \"tilt\", \"dolly\", \"handheld\", \"fast\", \"slow\"]\n_EMOTION_TAGS= list(_MOOD_KEYWORDS[\"mood_happy\"]) + list(_MOOD_KEYWORDS[\"mood_intense\"]) + list(_MOOD_KEYWORDS[\"mood_calm\"])\n\n# Hip-Hop HSV Visual Ranges\n_HIPHOP_COLOR_RANGES = {\n    \"gold\":        ([20, 100, 100], [35, 255, 255]),\n    \"neon\":        ([80, 150, 150], [140, 255, 255]),\n    \"red_accent\":  ([0, 120, 120],  [10, 255, 255]),\n}\n\n\n@dataclass\nclass ClipMetadata:\n    path: Path\n    duration: float\n    shot_type: str\n    movement: str\n    emotion_tags: List[str]\n    brightness: float\n    motion: float\n    hiphop_affinity: float\n    dominant_colors: List[Tuple[int, int, int]]\n    nfo_tags: str\n    vector: np.ndarray\n\n\nclass ClipPool:\n    \"\"\"Manages video clip library with 9D semantic vector analysis.\"\"\"\n    \n    def __init__(self, pool_dir: str, max_analysis_frames: int = 15):\n        self.pool_dir = Path(pool_dir)\n        self.max_frames = max_analysis_frames\n        self.clips: List[ClipMetadata] = []\n        self._recently_used: List[Path] = []\n        \n        self.db_path = Path(__file__).parent.parent / \"db\" / \"weedit_db.json\"\n        self.db_cache: Dict[str, dict] = {}\n        \n        self._load_database_cache()\n        self._load_and_analyze()\n\n    def _load_database_cache(self) -> None:\n        \"\"\"Loads pre-rendered analyses from json cache.\"\"\"\n        if self.db_path.exists():\n            try:\n                with open(self.db_path, \"r\", encoding=\"utf-8\") as f:\n                    data = json.load(f)\n                    if isinstance(data, list):\n                        for entry in data:\n                            if \"path\" in entry:\n                                filename = Path(entry[\"path\"]).name\n                                self.db_cache[filename] = entry\n                    elif isinstance(data, dict):\n                        self.db_cache = data\n                print(f\"✅ [ClipPool] Database loaded: {len(self.db_cache)} clips from cache\")\n            except Exception as e:\n                print(f\"⚠️ [ClipPool] Could not parse database: {e}\")\n\n    def _save_database_cache(self) -> None:\n        \"\"\"Saves current state back to disk atomically.\"\"\"\n        try:\n            self.db_path.parent.mkdir(parents=True, exist_ok=True)\n            output_list = []\n            for c in self.clips:\n                output_list.append({\n                    \"path\": str(c.path),\n                    \"duration\": c.duration,\n                    \"motion_score\": float(c.motion * 50.0),\n                    \"shot_scale\": c.shot_type,\n                    \"camera_movement\": c.movement,\n                    \"brightness\": float(c.brightness),\n                    \"dominant_colors\": c.dominant_colors,\n                    \"vector\": c.vector.tolist()\n                })\n            with open(self.db_path, \"w\", encoding=\"utf-8\") as f:\n                json.dump(output_list, f, indent=2)\n            print(f\"💾 [ClipPool] Database updated: {len(output_list)} clips saved\")\n        except Exception as e:\n            print(f\"⚠️ [ClipPool] Could not write database: {e}\")\n\n    def _load_and_analyze(self) -> None:\n        if not self.pool_dir.exists():\n            print(f\"❌ [ClipPool] Directory not found: {self.pool_dir}\")\n            return\n\n        modified_db = False\n        for fname in sorted(os.listdir(self.pool_dir)):\n            path = self.pool_dir / fname\n            if path.suffix.lower() not in VIDEO_EXTS:\n                continue\n            resolved = path.resolve()\n            if not resolved.exists():\n                continue\n\n            try:\n                if fname in self.db_cache:\n                    cached = self.db_cache[fname]\n                    cached_vector = cached.get(\"vector\", np.zeros(VECTOR_DIM).tolist())\n                    meta = ClipMetadata(\n                        path=resolved,\n                        duration=cached.get(\"duration\", 0.0),\n                        shot_type=cached.get(\"shot_scale\", \"medium\"),\n                        movement=cached.get(\"camera_movement\", \"static\"),\n                        emotion_tags=[],\n                        brightness=cached.get(\"brightness\", 127.0),\n                        motion=cached.get(\"motion_score\", 0.0) / 50.0,\n                        hiphop_affinity=cached_vector[0] if cached_vector else 0.0,\n                        dominant_colors=cached.get(\"dominant_colors\", []),\n                        nfo_tags=\"\",\n                        vector=np.array(cached_vector or [0]*VECTOR_DIM, dtype=np.float32)\n                    )\n                    self.clips.append(meta)\n                else:\n                    print(f\"🔍 [ClipPool] Analyzing new asset: {fname}\")\n                    meta = self._parse_target_clip(resolved, original_path=path)\n                    self.clips.append(meta)\n                    modified_db = True\n            except Exception as e:\n                print(f\"[ClipPool] Skipping {fname}: {e}\")\n\n        print(f\"📦 [ClipPool] Pool initialized: {len(self.clips)} clips ready\")\n        if modified_db:\n            self._save_database_cache()\n\n    def _parse_target_clip(self, path: Path, original_path: Optional[Path] = None) -> ClipMetadata:\n        disp_path = original_path or path\n        stem = disp_path.stem.lower()\n\n        words = re.split(r\"[\\W_]+\", stem)\n        shot_type = next((w for w in words if w in _SHOT_TAGS), \"medium\")\n        movement = next((w for w in words if w in _MOTION_TAGS), \"static\")\n        emotion_tags = [w for w in words if w in _EMOTION_TAGS]\n\n        nfo_text = \"\"\n        nfo_path = disp_path.with_suffix(\".nfo\")\n        if nfo_path.exists():\n            try:\n                with open(nfo_path, \"r\", encoding=\"utf-8\") as f:\n                    nfo = json.load(f)\n                nfo_text = \" \".join([\n                    \" \".join(nfo.get(\"tags\", [])),\n                    nfo.get(\"shot_scale\", \"\"),\n                    nfo.get(\"camera_movement\", \"\"),\n                ])\n                if nfo.get(\"shot_scale\"):\n                    shot_type = nfo[\"shot_scale\"]\n                if nfo.get(\"camera_movement\"):\n                    movement = nfo[\"camera_movement\"]\n            except Exception:\n                pass\n\n        brightness, motion, duration, hiphop_affinity, dominant_colors = self._evaluate_visual_properties(path)\n        all_text = f\"{stem} {nfo_text} {' '.join(emotion_tags)}\"\n        vector = self._compute_9d_vector(all_text, shot_type, movement, motion, hiphop_affinity)\n\n        return ClipMetadata(\n            path=disp_path,\n            duration=duration,\n            shot_type=shot_type,\n            movement=movement,\n            emotion_tags=emotion_tags,\n            brightness=brightness,\n            motion=motion,\n            hiphop_affinity=hiphop_affinity,\n            dominant_colors=dominant_colors,\n            nfo_tags=nfo_text,\n            vector=vector,\n        )\n\n    def _evaluate_visual_properties(self, path: Path) -> tuple:\n        cap = cv2.VideoCapture(str(path))\n        fps = cap.get(cv2.CAP_PROP_FPS) or 30.0\n        total = int(cap.get(cv2.CAP_PROP_FRAME_COUNT))\n        duration = total / fps if total > 0 else 0.0\n\n        step = max(1, total // self.max_frames)\n        brightness_samples: List[float] = []\n        motion_samples: List[float] = []\n        hiphop_scores: List[float] = []\n        prev_gray: Optional[np.ndarray] = None\n        sample_frame: Optional[np.ndarray] = None\n\n        for i in range(0, total, step):\n            cap.set(cv2.CAP_PROP_POS_FRAMES, i)\n            ret, frame = cap.read()\n            if not ret or frame is None:\n                break\n            \n            if sample_frame is None:\n                sample_frame = frame.copy()\n\n            gray = cv2.cvtColor(frame, cv2.COLOR_BGR2GRAY)\n            hsv = cv2.cvtColor(frame, cv2.COLOR_BGR2HSV)\n            \n            brightness_samples.append(float(np.mean(gray)))\n            if prev_gray is not None:\n                diff = cv2.absdiff(prev_gray, gray)\n                motion_samples.append(float(np.mean(diff)))\n            prev_gray = gray\n            hiphop_scores.append(self._calculate_hiphop_score(frame, hsv, gray))\n\n        cap.release()\n\n        colors = []\n        if sample_frame is not None:\n            colors = self._extract_palette_kmeans(sample_frame, k=3)\n\n        brightness = float(np.mean(brightness_samples)) if brightness_samples else 127.0\n        raw_motion = float(np.mean(motion_samples)) if motion_samples else 0.0\n        norm_motion = float(np.clip(raw_motion / 30.0, 0.0, 1.0))\n        hiphop_affinity = float(np.mean(hiphop_scores)) if hiphop_scores else 0.0\n\n        return brightness, norm_motion, duration, hiphop_affinity, colors\n\n    def _calculate_hiphop_score(self, frame: np.ndarray, hsv: np.ndarray, gray: np.ndarray) -> float:\n        h, w = frame.shape[:2]\n        pixel_count = h * w\n        score = 0.0\n\n        for color_name, (low, up) in _HIPHOP_COLOR_RANGES.items():\n            mask = cv2.inRange(hsv, np.array(low), np.array(up))\n            ratio = np.sum(mask > 0) / pixel_count\n            if color_name == \"gold\":\n                score += min(ratio * 10, 0.35)\n            elif color_name == \"neon\":\n                score += min(ratio * 8, 0.25)\n            elif color_name == \"red_accent\":\n                score += min(ratio * 5, 0.10)\n\n        contrast = np.std(gray)\n        if contrast > 60.0:\n            score += 0.15\n\n        edges = cv2.Canny(gray, 50, 150)\n        edge_ratio = np.sum(edges > 0) / pixel_count\n        if 0.08 < edge_ratio < 0.25:\n            score += 0.15\n\n        return min(score, 1.0)\n\n    def _extract_palette_kmeans(self, frame: np.ndarray, k: int = 3) -> List[Tuple[int, int, int]]:\n        try:\n            pixels = frame.reshape((-1, 3))\n            pixels = np.float32(pixels)\n            criteria = (cv2.TERM_CRITERIA_EPS + cv2.TERM_CRITERIA_MAX_ITER, 10, 1.0)\n            _, _, centers = cv2.kmeans(pixels, k, None, criteria, 10, cv2.KMEANS_RANDOM_CENTERS)\n            return [(int(c[2]), int(c[1]), int(c[0])) for c in centers]\n        except Exception:\n            return [(127, 127, 127)]\n\n    def _compute_9d_vector(\n        self,\n        text: str,\n        shot_type: str,\n        movement: str,\n        motion: float,\n        hiphop_affinity: float\n    ) -> np.ndarray:\n        vec = np.zeros(VECTOR_DIM, dtype=np.float32)\n        t = text.lower()\n\n        for idx, (genre, lst) in enumerate(_GENRE_KEYWORDS.items()):\n            vec[idx] = 1.0 if any(kw in t for kw in lst) else 0.0\n\n        if hiphop_affinity > 0.4:\n            vec[0] = max(vec[0], hiphop_affinity)\n\n        for idx, (mood, lst) in enumerate(_MOOD_KEYWORDS.items()):\n            vec[5 + idx] = 1.0 if any(kw in t for kw in lst) else 0.0\n\n        if shot_type in (\"close\",):\n            vec[6] = max(vec[6], 0.5)\n        if shot_type in (\"wide\", \"aerial\", \"drone\"):\n            vec[7] = max(vec[7], 0.5)\n\n        if movement in (\"static\",):\n            vec[7] = max(vec[7], 0.4)\n        if movement in (\"tracking\", \"handheld\", \"fast\"):\n            vec[6] = max(vec[6], 0.4)\n\n        vec[8] = float(motion)\n\n        return vec\n\n    def select_best_clip(\n        self,\n        min_duration: float,\n        query_vector: np.ndarray,\n        avoid_reuse: bool = True,\n        cooldown: int = 5\n    ) -> ClipMetadata:\n        cooldown = min(cooldown, max(1, len(self.clips) // 2))\n\n        candidates = [\n            c for c in self.clips\n            if c.duration >= min_duration\n            and (not avoid_reuse or c.path not in self._recently_used[-cooldown:])\n        ]\n\n        if not candidates:\n            self._recently_used = self._recently_used[(cooldown // 2):]\n            candidates = [c for c in self.clips if c.duration >= min_duration] or self.clips\n\n        if len(candidates) == 1:\n            chosen = candidates[0]\n        else:\n            q = query_vector.astype(np.float32)\n            scores = []\n            for c in candidates:\n                if np.linalg.norm(q) < 1e-8 or np.linalg.norm(c.vector) < 1e-8:\n                    scores.append(0.0)\n                else:\n                    scores.append(float(1.0 - cosine(q, c.vector)))\n\n            chosen = candidates[int(np.argmax(scores))]\n\n        self._recently_used.append(chosen.path)\n        return chosen\n